import{_ as e,o as t,c as i,a2 as s}from"./chunks/framework.BuL2a98s.js";const u=JSON.parse('{"title":"Práctica 17: seno DAC con frecuencia seleccionable","description":"","frontmatter":{},"headers":[],"relativePath":"examples/digital-labs/17_dac_r2r_frecuencia.md","filePath":"examples/digital-labs/17_dac_r2r_frecuencia.md"}'),d={name:"examples/digital-labs/17_dac_r2r_frecuencia.md"};function l(n,a,o,c,r,h){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="practica-17-seno-dac-con-frecuencia-seleccionable" tabindex="-1">Práctica 17: seno DAC con frecuencia seleccionable <a class="header-anchor" href="#practica-17-seno-dac-con-frecuencia-seleccionable" aria-label="Permalink to &quot;Práctica 17: seno DAC con frecuencia seleccionable&quot;">​</a></h1><h2 id="objetivo" tabindex="-1">Objetivo <a class="header-anchor" href="#objetivo" aria-label="Permalink to &quot;Objetivo&quot;">​</a></h2><p>Generar una onda sinusoidal en el DAC R-2R de 8 bits y controlar su frecuencia con los dos botones de la Tang Nano 9K: 500 Hz, 1 kHz, 1.5 kHz, 2 kHz, 3 kHz o 4 kHz. Estas frecuencias son apropiadas para observarse con un osciloscopio de 250 kS/s.</p><h2 id="controles" tabindex="-1">Controles <a class="header-anchor" href="#controles" aria-label="Permalink to &quot;Controles&quot;">​</a></h2><ul><li><code>key_down_n</code> (GPIO3): baja un nivel.</li><li><code>key_up_n</code> (GPIO4): sube un nivel.</li><li>El display muestra el nivel seleccionado de <code>01</code> a <code>06</code>.</li><li>El nivel inicial es <code>02 = 1 kHz</code>.</li><li>El contador se detiene al llegar al mínimo o al máximo.</li></ul><table tabindex="0"><thead><tr><th>Display</th><th style="text-align:right;">Frecuencia nominal</th><th style="text-align:right;">Incremento DDS</th></tr></thead><tbody><tr><td><code>01</code></td><td style="text-align:right;">500 Hz</td><td style="text-align:right;">79 536</td></tr><tr><td><code>02</code></td><td style="text-align:right;">1 kHz</td><td style="text-align:right;">159 073</td></tr><tr><td><code>03</code></td><td style="text-align:right;">1.5 kHz</td><td style="text-align:right;">238 609</td></tr><tr><td><code>04</code></td><td style="text-align:right;">2 kHz</td><td style="text-align:right;">318 146</td></tr><tr><td><code>05</code></td><td style="text-align:right;">3 kHz</td><td style="text-align:right;">477 219</td></tr><tr><td><code>06</code></td><td style="text-align:right;">4 kHz</td><td style="text-align:right;">636 291</td></tr></tbody></table><h2 id="flujo-dds" tabindex="-1">Flujo DDS <a class="header-anchor" href="#flujo-dds" aria-label="Permalink to &quot;Flujo DDS&quot;">​</a></h2><p>El acumulador de fase se actualiza en cada ciclo del reloj de 27 MHz:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>botones -&gt; índice 01..06 -&gt; incremento de fase</span></span>
<span class="line"><span>                                  |</span></span>
<span class="line"><span>reloj 27 MHz -&gt; acumulador DDS -&gt; LUT seno de 32 muestras -&gt; DAC R-2R</span></span></code></pre></div><p>La relación utilizada es:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>incremento = redondear(f_salida * 2^32 / 27 000 000)</span></span></code></pre></div><p>Con una captura de 250 kS/s, el osciloscopio obtiene aproximadamente 500 muestras por periodo a 500 Hz, 250 a 1 kHz, 167 a 1.5 kHz, 125 a 2 kHz, 83 a 3 kHz y 62 a 4 kHz.</p><h2 id="pinout" tabindex="-1">Pinout <a class="header-anchor" href="#pinout" aria-label="Permalink to &quot;Pinout&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Señal</th><th>Función</th><th style="text-align:right;">Pin FPGA</th></tr></thead><tbody><tr><td><code>clk</code></td><td>Reloj de 27 MHz</td><td style="text-align:right;">52</td></tr><tr><td><code>key_down_n</code></td><td>Disminuir frecuencia</td><td style="text-align:right;">3</td></tr><tr><td><code>key_up_n</code></td><td>Aumentar frecuencia</td><td style="text-align:right;">4</td></tr><tr><td><code>dac[7:0]</code></td><td>DAC, de MSB a LSB</td><td style="text-align:right;">51, 42, 41, 35, 40, 30, 34, 33</td></tr><tr><td><code>seg[7:0]</code></td><td>Segmentos</td><td style="text-align:right;">37, 25, 26, 28, 27, 36, 39, 38</td></tr><tr><td><code>digit_en[1:0]</code></td><td>Selección de dígito</td><td style="text-align:right;">32, 31</td></tr></tbody></table><h2 id="compilar" tabindex="-1">Compilar <a class="header-anchor" href="#compilar" aria-label="Permalink to &quot;Compilar&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> digital-labs/17_dac_r2r_frecuencia</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flash</span></span></code></pre></div><p>Para compilar la versión VHDL:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devlab-vhdl.toml</span></span></code></pre></div><h2 id="prueba-sugerida" tabindex="-1">Prueba sugerida <a class="header-anchor" href="#prueba-sugerida" aria-label="Permalink to &quot;Prueba sugerida&quot;">​</a></h2><ol><li>Conecta el osciloscopio a la salida de la red R-2R y comparte tierra.</li><li>Verifica que al encender el display indique <code>02</code> y se midan cerca de 1 kHz.</li><li>Pulsa el botón de incremento y compara cada nivel con la tabla.</li><li>Usa el botón de decremento hasta regresar a <code>01 = 500 Hz</code>.</li></ol><div class="warning custom-block"><p class="custom-block-title">Salida analógica</p><p>La salida GPIO es una aproximación escalonada de ocho bits. Usa una red R-2R con valores adecuados y, si necesitas una senoide más limpia, agrega un filtro pasa-bajas y un buffer; no conectes una carga de baja impedancia directamente.</p></div>`,21)])])}const g=e(d,[["render",l]]);export{u as __pageData,g as default};
